                  <span style={{ padding: "2px 8px", borderRadius: 14, fontSize: 10, fontWeight: 600, color: t.tier === "Premium" ? C.gold : C.cyan, background: t.tier === "Premium" ? `${C.gold}15` : `${C.cyan}15` }}>{t.tier}</span>
